import { test, expect } from '@playwright/test';

test('verify header links and navigation on mobile', async ({ page }) => {
  // Set mobile viewport 375x812
  await page.setViewportSize({ width: 375, height: 812 });

  // Navigate to the site
  await page.goto('http://localhost:3002/');

  // Define expected links and their targets
  const expectedLinks = [
    { name: /Oskar Site|Home/i, target: '/' },
    { name: /blog/i, target: '/blog' },
    { name: /portfolio/i, target: '/portfolio' },
    { name: /videos/i, target: '/videos' },
    { name: /contact/i, target: '/contact' }
  ];

  // Verify each link is present and has the correct target
  for (const link of expectedLinks) {
    const linkElement = page.getByRole('link', { name: link.name });
    await expect(linkElement).toBeVisible();
    const href = await linkElement.getAttribute('href');
    expect(href).toBe(link.target);
  }

  // Test clicking each link and verify navigation (Home link is 'Oskar Site')
  await page.getByRole('link', { name: 'blog' }).click();
  await expect(page).toHaveURL(/.*\/blog/);

  await page.getByRole('link', { name: 'portfolio' }).click();
  await expect(page).toHaveURL(/.*\/portfolio/);

  await page.getByRole('link', { name: 'videos' }).click();
  await expect(page).toHaveURL(/.*\/videos/);

  await page.getByRole('link', { name: 'contact' }).click();
  await expect(page).toHaveURL(/.*\/contact/);

  await page.getByRole('link', { name: 'Oskar Site' }).click();
  await expect(page).toHaveURL('http://localhost:3002/');
});
